request.query:
BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?tableType ?table ?tableName WHERE {
  {
    ?table rdf:type vocab:package .
  }
  UNION
  {
    ?table rdf:type vocab:block .
  }
  OPTIONAL { ?table rdf:type ?tableType }
  ?table vocab:NamedElement_name ?tableName .
  FILTER(CONTAINS(LCASE(STR(?tableName)), LCASE("wavefront")))
  FILTER(CONTAINS(LCASE(STR(?tableName)), LCASE("calibration")))
  FILTER(
    CONTAINS(LCASE(STR(?tableName)), LCASE("lookup table")) ||
    CONTAINS(LCASE(STR(?tableName)), LCASE("lookup")) ||
    CONTAINS(LCASE(STR(?tableName)), LCASE("table"))
  )
}
LIMIT 25
